lue(&amp;quot;$&amp;#123;user.name&amp;#125;&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private String name1;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Value(&amp;quot;$&amp;#123;user2.name&amp;#125;&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private String name2;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Value(&amp;quot;$&amp;#123;habits[1]&amp;#125;&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private String habit;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Value(&amp;quot;$&amp;#123;users[1].age&amp;#125;&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private Integer age;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Value(&amp;quot;$&amp;#123;tempDir&amp;#125;&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private String tempDir;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Value(&amp;quot;$&amp;#123;tempDir1&amp;#125;&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private String tempDir1;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    // 使用自动装配将所有的数据封装到Environment对象中&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Autowired&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private Environment env;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Autowired&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private MyDataSource dataSource;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @GetMapping&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public String getById() &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;springboot is running...&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;country1 = &amp;quot; + country1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;name1 = &amp;quot; + name1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;name2 = &amp;quot; + name2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;habit = &amp;quot; + habit);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;age = &amp;quot; + age);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;tempDir = &amp;quot; + tempDir);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;tempDir1 = &amp;quot; + tempDir1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;====================================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;country1 = &amp;quot; + env.getProperty(&amp;quot;country&amp;quot;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;name1 = &amp;quot; + env.getProperty(&amp;quot;user.name&amp;quot;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;name2 = &amp;quot; + env.getProperty(&amp;quot;user2.name&amp;quot;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;habit = &amp;quot; + env.getProperty(&amp;quot;habits[1]&amp;quot;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;age = &amp;quot; + env.getProperty(&amp;quot;users[1].age&amp;quot;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;tempDir = &amp;quot; + env.getProperty(&amp;quot;tempDir&amp;quot;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;tempDir1 = &amp;quot; + env.getProperty(&amp;quot;tempDir1&amp;quot;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;=====================================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;dataSource = &amp;quot; + dataSource);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return &amp;quot;springboot is running...&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2&gt;&lt;span id=&#34;整合-junit&#34;&gt; 整合 junit&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;创建模块，不勾选任何选项&lt;/li&gt;
&lt;li&gt;BookDao 接口&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public interface BookDao &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void save();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;BookDaoImpl 类&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;@Repository&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class BookDaoImpl implements BookDao &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Override&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void save()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;bookDao is running...&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;测试&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;// 如果测试类跟springboot运行引导类不在同一个包下，那么需要给@SpringBootTest注解加classes属性&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;@SpringBootTest(classes = Demo1Application.class)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;class Demo1ApplicationTests &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    // 1、注入要测试的对象&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Autowired&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private BookDao bookDao;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Test&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    void contextLoads() &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        // 2、执行要测试的对象对应的方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bookDao.save();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2&gt;&lt;span id=&#34;导入&#34;&gt; 导入&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;软件正在慢条斯理地吞噬世界，开源正在慢条斯理地吞噬软件业。&lt;/p&gt;
&lt;p&gt;软件正在吞噬世界？是的，对于购物、吃饭、健身、交停车费都需要使用软件的年代，对于平均每人每天都要花费 5 到 6 个小时使用手机软件的年代，有什么理由不相信软件正在吞噬整个世界呢。&lt;/p&gt;
&lt;p&gt;开源正在吞噬软件业？是的，因为在软件越来越富裕的年代（也即软件不再稀缺），不开源的软件，最终是没法和开源软件竞争的。举个简单例子，如果有人要在很多个文件加密软件中选择一个使用，在功能和价格都差不多的情况下，选择开源的还是闭源的？当然要选择开源的，因为谁知道闭源的软件中，会不会有后门？&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;例子&#34;&gt; 例子&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;开源的成功程度，或者说开源的渗透程度，从中国银行业的广泛采用就可以看出来，银行作为一个在 IT 方面相当谨慎和保守的行业，在 2012 年（一个大约的年限）之前对开源基本上不屑一顾，使用的基本上全是商业软件（这里是指专有软件），他们认为商业软件更专业、质量更高、更可信赖、更有保障，他们中不少人视开源软件为异类，对其功能、性能、安全性表示担忧，最重要的是，他们担心开源软件出问题后找不到 “原厂” 解决问题和 “承担责任”。&lt;/p&gt;
&lt;p&gt;然而就在 2012 年以后，银行业逐渐增加了开源的使用比例，这里面有很多原因，最重要的一个原因是，在 Linux 面世 20 年后，很多开源软件已经成为比商业软件更好的存在，以至于咨询商、集成商、开发商们在为银行提供解决方案时，所拿出的最佳方案已经是基于开源的方案，银行（作为甲方）已经无力拒绝。比如，如今当一个银行要建设其自用的云平台时，在咨询和调研一大圈下来，他几乎一定会选择基于 OpenStack 的方案，如果想使用容器技术，就几乎一定会选择容器编排软件 kubernetes，这时，已经顾不上有没有 “原厂” 了（事实上还是有服务商兜底），因为没有太多更好的选择了。&lt;/p&gt;
&lt;p&gt;银行虽然还在使用 Vmware、Oracle、Websphere、Weblogic，但是 KVM、Mysql、Apache、Nginx 的渗透已经越来越严重，多数银行的 Linux 主机数量早已超过了 Windows 服务器，因为 Linux 早已成为整个世界的主流的服务器操作系统，而且还有像 Redhat 这样的商业支持，为什么不使用呢。&lt;/p&gt;
&lt;p&gt;如果有条件，你可以实地调查一下，各家银行的 IT 部门，在最近 5 年内，已经不得不正面开源这种 “新事物” 给他们带来的 “问题”，因为对开源的引入、使用和运维，显然和以往闭源软件有明显不同，他们开始写出开源软件使用管理办法，并指定专门处室来负责管理。&lt;/p&gt;
&lt;p&gt;而那些有先见之明的企业（尤其是互联网企业），早已组建了开源办公室，早已把自己的整个系统建立在开源软件之上，并且早已在开源世界投入了大量的资金和人员，毫无疑问，他们也早已从开源中获得了巨大的收益。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;开源取得成功的七大理念&#34;&gt; 开源取得成功的七大理念&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;完全自主&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;程序员想要开源的操作系统，想要开源的编辑器，还想要开源的编译器、开源的浏览器、开源的数据库、开源的 web server、开源的云环境、开源的虚拟机软件、开源的大数据工具、开源的人工智能软件。。。总之，如果一切都开源了，这就是程序员感觉最自由和最自主的环境，这就是程序员的理想。&lt;/p&gt;
&lt;p&gt;如果很多人都有这样的需求，而又有人能把它实现，那这件事就必然会发生。&lt;/p&gt;
&lt;p&gt;当程序员们想要开源操作系统的时候，Tanenbaum 带着 Minix 出现了，当人们希望它有更多的特性时，Linus 拿出了 Linux，当人们需要 web server 时，NCSA 拿出了 Apache，作者一开始开源自己的代码时，并没有想太多，可能仅仅就是想说：“兄弟们，看看我写的这个东西怎么样？你们试试用一下？有啥问题，或者有什么新想法，欢迎给我发邮件！”&lt;/p&gt;
&lt;p&gt;在需求和供应的动力下，开源从底层的操作系统开始，充满了整个开发环境和中间件，一直到最上层应用，只要是人们想要的东西，黑客就会把它们实现，如果有一样东西还没有开源，那一定还不是黑客很想要的东西，或者是，他们认为这个东西没有必要开源（比如赖以赚钱和生存的东西，比如比较客户化的东西）。&lt;/p&gt;
&lt;p&gt;所以，我们看到，操作系统 Linux、Android；编辑器 Vim、Emacs、Atom、Brackets、VS code，版本管理系统 SVN、Git；数据库 MySQL、MongoDB、Redis、Postgres；大数据平台 Hadoop、Elasticsearch、Hbase、Spark；Web 服务器 Apache、Nginx、Node.js、Tomcat；DevOps 工具 Jenkins、Maven、Ansible、Chef；虚拟化软件 KVM、Xen、Docker、Kubernetes，如雨后春笋般应运而生，这些列出的和没有列出的开源软件，形成了一个完整的软件生态环境，黑客们已经生活在一个很幸福的时代，他几乎是想要什么就有什么，而几乎在所有的 IT 企业和大型非 IT 企业里，你都能看到这些开源软件的身影。&lt;/p&gt;
&lt;p&gt;开源，其实是程序员送给程序员的礼物。&lt;/p&gt;
&lt;p&gt;因为真正需要源码的人，是程序员，真正能写出源码的人，也是程序员。&lt;br&gt;
2. 高度开放&lt;/p&gt;
&lt;p&gt;最开放的情况莫过于 “任何人能干任何事”（anyone can hack anything），也即没有任何事情可以阻止人们运行该产品，获取其源码、复制其源码、修改其源码，推进其向不同方向演进，并声称是该产品。&lt;/p&gt;
&lt;p&gt;这可是太过开放了，以至于拿到他人源码后，“克隆” 或者 “山寨” 出一个产品将没有任何法律层面的压力，为什么开源会开放到如此地步？&lt;/p&gt;
&lt;p&gt;一方面，在源码已经开放的前提下，你事实上很难阻止别人克隆、修改你的代码并换个名字发布。虽然程序员通常不会这么做，但他们不愿意有限制，在一个普遍宽松的环境下，如果你限制太多，程序员就不太会参与你的项目。&lt;/p&gt;
&lt;p&gt;另一方面，这是一个鼓励充分竞争的世界，如果程序员们就项目的方向产生分歧，而又无法达成一致，异见者就可以分叉出来自立门户。比如，EGCS 分叉自 GCC，OpenSSH 脱胎于走向商业化前的 SSH，Veracrypt 派生自 Truecrypt，再如近年来比较著名的事件：一些人不认可 BTC 的方向，分叉出来 BCH，然后又有人不认可 BCH，分叉出来 BSV，虽然这个过程中有很多争吵，但没有人可以阻止这些。&lt;br&gt;
3. 自发自治&lt;/p&gt;
&lt;p&gt;所谓开源社区，指的是所有关心、参与、支持、帮助某个开源项目的人的集合。&lt;/p&gt;
&lt;p&gt;社区里的人，是自发组织在一起的。“其中 90% 是用户，他们只是搭顺风车或是凑凑热闹，9% 的人积极参与、提交 bug、回答问题，这是‘贡献者’，1% 的人指导并控制项目的走向，委派任务和做决策，这是‘维护者’，或者简单的说，他们是领导者。”&lt;/p&gt;
&lt;p&gt;1、领导者（Leader）：比如 Linus Torvalds，作为内核的创始人，毫无疑问是该项目的最高领导者，在理论上，对 Linux 内核的任何事务都拥有最终话语权。在另外的一些项目中，可能有一个或多个人共同负责，如 Node.js 项目采用的是核心技术委员会机制（the Core Technical Committee）。&lt;/p&gt;
&lt;p&gt;2、维护者（Maintainer）：领导者会将一些决策和模块直接委托给维护者，维护者还可以将其中部分工作再委托给下一个层级的维护者。例如，Linus Torvalds 手下就有若干位内核的维护者，负责不同的模块。&lt;/p&gt;
&lt;p&gt;3、提交者（Committer）：有些开源项目会设置一组可以直接提交代码到主干的人，他们已经证明了自己可以胜任工作并且靠谱，而且不再需要提交维护者去进行审核。但提交者对代码没有最终的决定权，维护者或项目的领导者如果发现了什么，可以将提交的内容打回去。&lt;/p&gt;
&lt;p&gt;4、贡献者（Developer 或 Contributor）：贡献者可以做很多事，比如帮助解答用户的问题，贡献代码或文档，在邮件列表中参与讨论，也可以提交代码 committer。与前面的角色相比，贡献者对于代码的权力要小一些。&lt;/p&gt;
&lt;p&gt;5、使用者（User）：用户为项目提供了目标，并帮助项目持续进化，作为社区成员，他们最有价值的部分是提出需求、报告缺陷、提出建议。&lt;/p&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;自下而上&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;自下而上是大自然最普遍的法则，开源作为一个从草根社会发展起来的事物，必然会遵循这个法则。&lt;/p&gt;
&lt;p&gt;在开源世界里，至少可以从技术、生态、成就三个层面来观察这一现象。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;技术&lt;br&gt;
纵观开源历史，那些非常富有创意的软件，一开始都是作者脑海中一个不太清晰、朦朦胧胧的想法，然后在作者能力和经验的基础上，通过代码一步步明晰起来的。开源项目在第一次露面时，大多数情况下只是初步可以运行，然后通过其富有创意的特性和前景，吸引更多的程序员关注和贡献。&lt;/li&gt;
&lt;li&gt;生态&lt;br&gt;
开源软件之间形成的关系，也是自下而上的，先有了语言、编译器、操作系统，然后在操作系统提供的各种功能的基础上（比如文件系统、内存系统、硬件驱动等），黑客做出了实用工具（binutils），做出外壳（Shell），做出了代码管理工具、集成开发环境，做出了数据库、Webserver、浏览器，做出了虚拟机，做出了 javascript，做出了包管理工具，做出各种应用开发框架和组件，做出了大数据、云技术，做出了各种面向最终用户的应用。程序员总是先做出底层的东西，然后才做出上层的东西，而且总是先有实践，才有了理论，总是先有代码，才有了设计模式、架构体系、软件工程这些东西。&lt;/li&gt;
&lt;li&gt;成就&lt;br&gt;
绝大多数黑客，一开始都是小打小闹，从简陋的程序开始起家，并没有什么宏大的想法，Linus 一开始也只是自己玩玩看（《Just For Fun》），并没有想着要怎么改变世界，说自己 “如果当时真的知道从头建立一个操作系统的难度，肯定是不会有勇气去做的”12。而到了 1999 年，Linus 在 “The Linux Edge” 一文中提到：“Linux 现在有数百万用户、数千名开发者和正在增长的市场，Linux 被用在嵌入式系统中，用在机器人系统中，用在航天飞机上，我想说我知道这些都会发生，这些都是统领世界计划的一部分（that it’s all part of the plan for world domination）”，虽然，这也许只是一种诙谐的表达。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;自由竞争&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;开源，是一个靠实力说话的世界。&lt;/p&gt;
&lt;p&gt;开源软件在竞争什么？竞争的是谁的软件好使，谁的评价更高，以及，最终，是谁获得了更多的市场份额。&lt;/p&gt;
&lt;p&gt;软件在竞争，个人也在竞争。&lt;/p&gt;
&lt;p&gt;个人竞争的法则很简单，如果你的贡献 —— 当然主要是指代码的贡献 —— 得到了同侪认可，你就会获得声誉和权力。&lt;br&gt;
6. 赢在声誉&lt;br&gt;
 7. 社区赋能&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;开源盈利&#34;&gt; 开源？盈利？&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;开源怎么赢利？抛开开源的商业模式不提，我想，只要我们开源的代码真正创造了价值，有人用，那我和团队就是最大的赢家。如果 30 年后，还有人在用 TDengine, 哪怕只是其中一个模块，其中一个函数，那就是对我们两年多日夜奋战的最大肯定，就是给我这个程序员的最大回报。&lt;/p&gt;
&lt;p&gt;如果你发现什么问题，我只会高兴，不睡觉都想尽快去解决它。如果喜欢，更欢迎参与到我们这个项目中来。五年之内，世界上 90% 以上的数据都将是物联网采集的数据，如果我们一起开发出一个极为高效的数据处理引擎来处理这些数据，而且为全球开发者所使用，你是贡献者之一，那是一个多么自豪的事情。”&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;关于开源&#34;&gt; 关于开源&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;开源软件在追求 “自由” 的同时，不能牺牲程序员的利益，否则将会影响程序员的创造激情，因此世界上现在有 60 多种被开源促进组织（Open Source Initiative）认可的开源许可协议来保证开源工作者的权益。&lt;/p&gt;
&lt;p&gt;开源协议规定了你在使用开源软件时的权利和责任，也就是规定了你可以做什么，不可以做什么。&lt;/p&gt;
&lt;p&gt;开源协议虽然不一定具备法律效力，但是当涉及软件版权纠纷时，开源协议也是非常重要的证据之一。&lt;/p&gt;
&lt;p&gt;对于准备编写一款开源软件的开发人员，也非常建议先了解一下当前最热门的开源许可协议，选择一个合适的开源许可协议来最大限度保护自己的软件权益。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;常见开源协议&#34;&gt; 常见开源协议&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;GNU GPL（GNU General Public License，GNU 通用公共许可证）&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;只要软件中包含了遵循 GPL 协议的产品或代码，该软件就必须也遵循 GPL 许可协议，也就是必须开源免费，不能闭源收费，因此这个协议并不适合商用软件。&lt;/p&gt;
&lt;p&gt;遵循 GPL 协议的开源软件数量极其庞大，包括 Linux 系统在内的大多数的开源软件都是基于这个协议的。&lt;/p&gt;
&lt;p&gt;GPL 开源协议的主要特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;复制自由：允许把软件复制到任何人的电脑中，并且不限制复制的数量。&lt;/li&gt;
&lt;li&gt;传播自由：允许软件以各种形式进行传播。&lt;/li&gt;
&lt;li&gt;收费传播：允许在各种媒介上出售该软件，但必须提前让买家知道这个软件是可以免费获得的；因此，一般来讲，开源软件都是通过为用户提供有偿服务的形式来盈利的。&lt;/li&gt;
&lt;li&gt;修改自由：允许开发人员增加或删除软件的功能，但软件修改后必须依然基于 GPL 许可协议授权。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;BSD（Berkeley Software Distribution，伯克利软件发布版）协议&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;BSD 协议基本上允许用户 “为所欲为”，用户可以使用、修改和重新发布遵循该许可的软件，并且可以将软件作为商业软件发布和销售，前提是需要满足下面三个条件：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果再发布的软件中包含源代码，则源代码必须继续遵循 BSD 许可协议。&lt;/li&gt;
&lt;li&gt;如果再发布的软件中只有二进制程序，则需要在相关文档或版权文件中声明原始代码遵循了 BSD 协议。&lt;/li&gt;
&lt;li&gt;不允许用原始软件的名字、作者名字或机构名称进行市场推广。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;BSD 对商业比较友好，很多公司在选用开源产品的时候都首选 BSD 协议，因为可以完全控制这些第三方的代码，甚至在必要的时候可以修改或者二次开发。&lt;br&gt;
3. Apache 许可证版本（Apache License Version）协议&lt;/p&gt;
&lt;p&gt;Apache 和 BSD 类似，都适用于商业软件。Apache 协议在为开发人员提供版权及专利许可的同时，允许用户拥有修改代码及再发布的自由。&lt;/p&gt;
&lt;p&gt;现在热门的 Hadoop、Apache HTTP Server、MongoDB 等项目都是基于该许可协议研发的，程序开发人员在开发遵循该协议的软件时，要严格遵守下面的四个条件：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;该软件及其衍生品必须继续使用 Apache 许可协议。&lt;/li&gt;
&lt;li&gt;如果修改了程序源代码，需要在文档中进行声明。&lt;/li&gt;
&lt;li&gt;若软件是基于他人的源代码编写而成的，则需要保留原始代码的协议、商标、专利声明及其他原作者声明的内容信息。&lt;/li&gt;
&lt;li&gt;如果再发布的软件中有声明文件，则需在此文件中标注 Apache 许可协议及其他许可协议。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;MIT（Massachusetts Institute of Technology）协议&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;目前限制最少的开源许可协议之一（比 BSD 和 Apache 的限制都少），只要程序的开发者在修改后的源代码中保留原作者的许可信息即可，因此普遍被商业软件所使用。&lt;/p&gt;
&lt;p&gt;使用 MIT 协议的软件有 PuTTY、X Window System、Ruby on Rails、Lua 5.0 onwards、Mono 等。&lt;br&gt;
5. GUN LGPL（GNU Lesser General Public License，GNU 宽通用公共许可证）&lt;/p&gt;
&lt;p&gt;LGPL 是 GPL 的一个衍生版本，也被称为 GPL V2，该协议主要是为类库设计的开源协议。&lt;/p&gt;
&lt;p&gt;LGPL 允许商业软件通过类库引用（link）的方式使用 LGPL 类库，而不需要开源商业软件的代码。这使得采用 LGPL 协议的开源代码可以被商业软件作为类库引用并发布和销售。&lt;/p&gt;
&lt;p&gt;但是如果修改 LGPL 协议的代码或者衍生品，则所有修改的代码，涉及修改部分的额外代码和衍生的代码都必须采用 LGPL 协议。因此 LGPL 协议的开源代码很适合作为第三方类库被商业软件引用，但不适合希望以 LGPL 协议代码为基础，通过修改和衍生的方式做二次开发的商业软件采用。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;如何选择开源协议&#34;&gt; 如何选择开源协议&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;世界上的开源协议有上百种（有兴趣的读者请猛击这里了解），很少有人能彻底搞清它们之间的区别，即使在最流行的六种开源协议 ——GPL、BSD、MIT、Mozilla、Apache 和 LGPL—— 之中做选择，也很复杂。&lt;/p&gt;
&lt;p&gt;乌克兰程序员 Paul Bagwell 画了一张分析图，说明应该怎么选择开源协议，大家看了一目了然，真是清爽。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;开源等于免费吗&#34;&gt; 开源等于免费吗&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;首先，开源软件和免费软件是两个概念：&lt;/p&gt;
&lt;p&gt;开源软件是指公开源代码的软件。开源软件在发行的时候会附上软件的源代码，并授权允许用户更改、传播或者二次开发。&lt;/p&gt;
&lt;p&gt;免费软件就是免费提供给用户使用的软件。但是在免费的同时，通常也会有一些限制，比如源代码不公开，用户不能随意修改、不能二次发布等。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;免费软件的例子比比皆是，QQ、微信、迅雷、酷狗、360 等都是免费软件，你可以随意使用，尽情蹂躏；但是，如果你嫌弃它们复杂，自己删除了一些无用的功能，然后在网上发布了一个精简版本供大家下载，那么你就离法院的传票不远了。&lt;/li&gt;
&lt;li&gt;开源软件是不抵触商业的，开源的目的也不是做慈善事业，而是通过更多人的参与，减少软件的缺陷，丰富软件的功能，同时也避免了少数人在软件里留一些不正当的后门。开源软件最终还会反哺商业，让商业公司为用户提供更好的产品。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Android 就是大众最熟知的一款开源操作系统，它除了用在手机上，还用在汽车、平板电脑、电视、智能手表等其它硬件平台，小米、华为、OPPO、三星等都是 Android 的受益者，他们都赚得盆满钵满。&lt;/p&gt;
&lt;p&gt;很多著名的开源项目背后都有商业公司支撑，它们的开发者也都有正式的工作，享受和我们一样的社会福利；如果一个成功的开源项目背后没有商业公司，这反而是不健康的，社会需要开源和商业之间的互补来促进技术的革新。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;不可忽视的安全隐患&#34;&gt; 不可忽视的安全隐患&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;就在刚刚过去的 2021 年，技术圈传出了一个爆炸性的新闻，Log4j 安全漏洞影响了上亿家公司，造成了无法计量的损失，使无数的程序员度过了一个难熬的不眠夜。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Log4J 是一个应用非常广泛的Java库，就在前两天的2021年12月10日，Log4J的一个安全漏洞被公布了。那天正好是周五，很多程序员都在计划着怎么度过一个愉快的周末，不料这个安全漏洞的公开，使得全世界很多程序员不得不周末加班，有的甚至通宵达旦紧急应对。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;漏洞编号为CVE-2021-44228 ，攻击者利用这个新的零日漏洞，可以远程执行恶意代码。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;零日漏洞（ zero-day ）通常是指还没有补丁的安全漏洞。零日漏洞利用（zero-day exploit）的程序对网络安全具有巨大威胁，因此零日漏洞不但是黑客的最爱，掌握多少零日漏洞也成为评价黑客技术水准的一个重要参数。&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;正是因为开源技术 “开放” 和 “自由” 的特点，它也更容易成为居心叵测之人下手的目标。黑客们有机会对项目的源代码进行分析、修改，并使用各种方法来遮盖对开源项目做出的恶意更改。再加上代码审查的严格程度因项目而异， 如果没有严格的审查措施来检测这些恶意更改，它们很容易就会被忽视，直到它们扩散开来，被使用在众多公司的软件中。&lt;/p&gt;
&lt;p&gt;与 Log4j 类似的情况比比皆是。EspoCRM，Pimcore，Akaunting 作为三个被数千家公司使用的开源软件，在企业的用户关系管理、客户数据管理、数字资产管理以及财会方面发挥着至关重要的作用。它们也曾被爆出致命漏洞，成功利用这些漏洞可以使绕过身份验证的攻击者执行任意 JavaScript 代码，控制底层操作系统并发起额外的恶意攻击，还可以通过特制的 HTTP 请求触发拒绝服务，甚至更改与用户账户关联的公司，且无需任何授权。&lt;/p&gt;
&lt;p&gt;在 2014 年席卷整个互联网世界的 OpenSSL Heartbleed（心脏出血）漏洞，不仅让整个中国互联网为之一颤，而且导致全球超过三分之二的网站 “心脏出血”，使全球互联网大量私钥和其他加密信息处于暴露危险下，受影响严重的系统甚至可以从服务器中直接获取用户密码。这一起起的开源安全事故，无不在印证着开源技术的安全风险。&lt;/p&gt;
&lt;p&gt;虽然开源技术确实很容易成为黑客们攻击的目标，但是我们还是可以通过一些手段，来中和使用开源技术带来的安全风险，把可能的损失降到最低。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;测试和制度&lt;br&gt;
首先，完善的测试和应急响应制度可以让企业更早的发现开源技术中的漏洞，更快的对其进行响应。 这主要分为三个部分：代码扫描和测试，建立一个明确的流程来解决和修复出现的漏洞、将解决安全问题的规则包含在公司策略中 bing。&lt;/li&gt;
&lt;li&gt;开源技术安全需要行业共同努力&lt;br&gt;
其实，目前包括 Linux，Apache 这样的顶级开源基金会都在呼吁大家重视开源技术的安全，并也付出了努力。包括资金的支持、开发安全工具、培训、研究和最佳实践。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;除了全行业努力保护基于开源代码构建的软件免受威胁外，企业也要对其防御战略有一个积极的态度。包括积极的为他们所依赖的开源代码实施测试并将数据积极向上游反馈。企业也应该制定合理的内部政策和指南，来识别使用开源软件的风险。如此做可以让企业继续利用开源代码的优势，同时也能创建一个能够预防可能威胁的环境。&lt;/p&gt;

 &lt;h2&gt;&lt;span id=&#34;爬虫简介&#34;&gt; 爬虫简介&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;什么是爬虫&lt;br&gt;
通过编写程序，模拟浏览器上网，然后让其去互联网上抓取数据的过程&lt;/li&gt;
&lt;li&gt;爬虫的价值&lt;br&gt;
爬取的数据&lt;/li&gt;
&lt;/ol&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;爬虫合法性探究&#34;&gt; 爬虫合法性探究&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;在法律中不被禁止&lt;/li&gt;
&lt;li&gt;具有违法风险&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;爬虫初探&#34;&gt; 爬虫初探&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;爬虫在使用场景中的分类&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;通用爬虫：抓取系统重要组成部分，抓取一整张页面数据&lt;/li&gt;
&lt;li&gt;聚焦爬虫：建立在通用爬虫基础之上，抓取的是页面中特定的局部内容&lt;/li&gt;
&lt;li&gt;增量式爬虫：检测网站中数据更新的情况，只会抓取网站中最新更新出来的数据&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;爬虫的矛与盾&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;反爬机制&lt;br&gt;
门户网站，可以通过制定相关的策略或者技术手段，防止爬虫程序进行网站数据的爬取&lt;/li&gt;
&lt;li&gt;反反爬策略&lt;br&gt;
破解门户网站的反爬机制，从而获取门户网站信息&lt;/li&gt;
&lt;li&gt;robots.txt 协议：&lt;br&gt;
君子协议：规定了网站中的哪些数据可以被爬虫爬取哪些数据不可以被爬取&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;http-和-https-协议&#34;&gt; http 和 https 协议&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;http 协议&lt;br&gt;
就是服务器和客户端进行数据交互的一种形式。&lt;/li&gt;
&lt;/ol&gt;

 &lt;ol&gt;
&lt;li&gt;与操作系统的兼容性&lt;br&gt;
最新版本的 WPS 对 Windows (Win2000-Win10)、Linux、Mac、Android (Android4.0 或更高版本)、iOS (iOS 所有的 iphone 固件版本以上，iOS 12 及以上) 都表示支持&lt;br&gt;
 PDF 新增：兼容系统控件中的功能（长按取词、复制、朗读，定义）&lt;/li&gt;
&lt;li&gt;与数据的兼容性&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;不同版本间的数据兼容性&lt;br&gt;
支持新旧版本界面风格随时切换&lt;br&gt;
一般来说高版本支持低版本，但是高版本中出现一些新功能，在低版本中可能会出现一些小问题&lt;/li&gt;
&lt;li&gt;不同软件间的数据兼容性&lt;br&gt;
与 Microsoft Office 中的 Word，Excel，PowerPoint 一一对应，应用 XML 数据交换技术，无障碍兼容 docx.xlsx.pptx，pdf 等文件格式，你可以直接保存和打开 Microsoft Word、Excel 和 PowerPoint 文件，也可以用 Microsoft Office 轻松编辑 WPS 系列文档。&lt;br&gt;
无隔阂兼容 MS-Office 加密信息、宏文档 内容互联、知识分享 —— 以提升效率为核心的互联网应用 。（文档方面）&lt;br&gt;
支持.ppt.pptx.pot.potx.pps.dps.dpt 等文件格式的打开和播放，包括加密文档（演示方面）&lt;br&gt;
支持 Airplay、DLNA 播放 PPT&lt;br&gt;
 支持 xls、xlt、xlsx、xltx、et、ett 等格式的查看，包括加密文档（表格方面）&lt;br&gt;
支持金山快盘、Dropbox、Box、GoogleDrive、SkyDrive、WebDAV 等多种主流网盘&lt;/li&gt;
&lt;/ul&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;与浏览器的兼容性&lt;br&gt;
各大浏览器只要设置兼容后，基本都可以打开&lt;/li&gt;
&lt;li&gt;与中间件的兼容性&lt;/li&gt;
&lt;li&gt;与平台软件的兼容性&lt;br&gt;
（4.5 具体体现在下面这些详细版本）&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;个人版&lt;br&gt;
高版本的 wps office 基本上可以兼容各版本的 Microsoft office。&lt;br&gt;
除了在文档格式上兼容，WPS 在使用习惯、界面功能上，都与微软 Office 深度兼容&lt;/li&gt;
&lt;li&gt;校园版&lt;br&gt;
全面兼容 Office 格式，新增 PDF 组建支持&lt;br&gt;
论文查重：多平台选择，计算重复率，定位到重复段落，提供参考性替换内容&lt;br&gt;
简历助手：多平台选择简历模板库，一次填写，一键投递&lt;/li&gt;
&lt;li&gt;专业版&lt;br&gt;
不仅在操作界面上与微软 Office 兼容，还支持直接打开和保存为微软 Office 格式的文档，同时，WPS Office 成熟的二次开发平台，保证了与微软 Office 一致的二次开发接口、API 接口、对象模型，兼容的 VBA 环境，支持 COM 加载插件等机制，实现了平滑迁移现有的电子政务平台、应用系统。&lt;br&gt;
支持 XML 标准：支持 OOXML、UOF2.0 (最新版标文通)，遵循 XML 标准，让政府和企业办公中的数据交换与数据检索更方便高效。&lt;br&gt;
WPS Office 提供了多套风格不同的界面，在经典界面与新界面之间，用户可以无障碍转换。&lt;/li&gt;
&lt;li&gt;租赁版&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;轻办公版本&lt;br&gt;
桌面客户端、网页端、移动端的多平台访问&lt;br&gt;
跨平台：有了云服务，便可以随时随地在你使用的任何设备上创建编辑文档。&lt;/li&gt;
&lt;li&gt;印象笔记版本&lt;br&gt;
可以在 2013 界面与旧版本界面之间切换，提供主题多样化选择。&lt;/li&gt;
&lt;li&gt;imo 版本&lt;br&gt;
对企业所需要的一系列功能都兼容，不在只限于文档、ppt 等内容，可以包括电子公告、企业邮箱、电子投票、电子考勤、日程提醒、网络文件柜、远程协助、群发文件传输等&lt;/li&gt;
&lt;li&gt;搜狐云存储版本&lt;br&gt;
支持 web 端、PC 端、移动端多平台数据同步，实现数据无缝对接，随时随地访问云端文件，轻松实现移动办公。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;移动版&lt;br&gt;
兼容 Android、iOS 操作系统&lt;br&gt;
支持微软 Office、PDF 等 47 种文档格式&lt;br&gt;
支持查看和编辑 doc/docx 文档（文字）&lt;br&gt;
支持 xls/xlsx 文档的查看和编辑，以及多种 Excel 加解密算法，已支持 305 种函数和 34 种图表模式（表格）&lt;br&gt;
支持 ppt/pptx 文档的查看、编辑和加解密，支持复杂的 SmartArt 对象和多种对象动画 / 翻页动画模式。（演示）&lt;br&gt;
使用支持 Miracast、DLNA 和米联的手机或平板电脑即可使用无线投影功能将文档投影在电视和投影仪上。（演示）&lt;/li&gt;
&lt;li&gt;移动专业版&lt;br&gt;
通过成熟的 SDK 接口技术兼容 OA、ERP、财务等系统的移动端应用开放的 SDK 机制，实现成熟的系统集成。WPS Office 移动专业版具备的 API 接口不仅开放而且高效易用；无论在 iOS 平台还是 Android 平台，WPS Office 都提供成熟的 SDK 方案，能够与移动 OA、ERP、CRM 等系统的安全交互。&lt;/li&gt;
&lt;li&gt;Android 版&lt;br&gt;
金山 WPS Office 移动版支持多种文档格式，如 doc、docx、wps、xls、xlsx、et、ppt、dps、pptx、txt…… 文档的查看及编辑。（文档）&lt;br&gt;
支持 xlsx 格式文档批注查看、插入以及保存新增，持打开 xml 格式文档。（表格）&lt;br&gt;
兼容显示及保存 pptx 格式文档中的自选图形（演示）&lt;/li&gt;
&lt;li&gt;IOS 版&lt;br&gt;
没查到。。。&lt;br&gt;
网上反馈的一些兼容性小问题&lt;br&gt;
 1、电脑端字体调整好在具体的某一页，在手机端会造成格式上调或者下调。&lt;br&gt;
2、WPS 插入 Excel 表的时候不是全部自动化的，需要自己调整表格，还要裁剪。&lt;br&gt;
3、Excel 导入图表时，手机端与电脑端的图片效果不一致。&lt;br&gt;
4、wps 中 ppt 的动画效果 &amp;quot;平滑&amp;quot; 效果没有。&lt;br&gt;
5、office 中 PPT 支持插入 3D 模型、动态 3D、动态 3D 的多个视角&lt;br&gt;
 6、office 中 PPT 的设计灵感功能强大 (将图片一键排版、人脸识别技术进行智能裁剪、纯文本 PPT 进行排版&lt;br&gt;
 7、wps 对第三方软件的兼容性较小，有一些插件根本不能用 (wps 是开源软件，跟很多第三方开源软件没有建立联系，用起来很棘手）&lt;br&gt;
8、WPS 没有适配触屏操作，在上课一体机触屏操作不好用&lt;/li&gt;
&lt;/ul&gt;

 &lt;h2&gt;&lt;span id=&#34;准备&#34;&gt; 准备&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;从噪音污染的例子引入话题，引入降噪，简单讲述降噪的历史发展&lt;br&gt;
物理原理简单了解  (图理结合)&lt;br&gt;
 降噪类型 (图理结合)&lt;br&gt;
 涉及计算机领域的知识&lt;br&gt;
降噪耳机对我们生活影响 (健康、价格、使用范围、优缺点、目前发展趋势)&lt;br&gt;
 qq 视频，软件实现降噪？&lt;br&gt;
大家 (知乎、各论坛、各种研究学者) 对降噪耳机的看法，我的看法&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;噪音污染&#34;&gt; 噪音污染&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;噪音的来源非常多，飞机或汽机车等交通工具、工厂、工地、日常生活都会产生噪音，因此噪音可以说是无处不在。噪音被归类为环境污染之一，在法律上被政府具体量化噪音标准。&lt;/p&gt;
&lt;p&gt;自工业革命开始，地球上的环境噪音不断在增加，噪音不只会干扰交谈及生活更会衍生出健康与安全问题，因此才会有 ANC 主动降噪的需求，进而有科学家研究理论及研发降噪功能。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;发展过程&#34;&gt; 发展过程&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;1936 年，德国物理学家卢埃格提出了主动降噪的概念，还申请了专利，但是欧洲专利有效期只有 20 年，所以还没有等到用主动降噪专利赚钱，专利期就到了，这也没什么，就像电脑技术，1946 年就在美国宾夕法尼亚大学问世，但是真正的商用也是 1971 年。&lt;/p&gt;
&lt;p&gt;小故事：1978 年，一个男人在欧洲飞往波士顿的飞机上，本来想听一点音乐，但是飞机引擎的噪音破坏了雅兴，因此下飞机后直奔麻省的公司，开始推导演算，写出了主动降噪耳机最原始的方程式，后来他调集核心研发团队，开启了降噪科技的研究，这个男人就是 Bose 的创始人，Amar G. Bose 博士。&lt;/p&gt;
&lt;p&gt;经过 11 年的研发 1989 年，首款商用 Bose 降噪耳机才诞生，这只是商用，并不是民用，最早只应用于军事领域，专供飞行员使用，受到了美国军方的追捧。&lt;/p&gt;
&lt;p&gt;直到 2000 年，Bose 具有了稳定的商用市场后，Bose 的工程师开始将主动降噪技术应用到民用耳机，紧接着推出了大名鼎鼎的 QC 降噪耳机系列，把降噪耳机推向了普通大众。&lt;/p&gt;
&lt;p&gt;降噪耳机领域，另一个大厂就是索尼，索尼一直扮演最佳配角，直到 2016 年 8 月，索尼发布了头戴式无线降噪耳机 MDR-1000X，此款产品让索尼与 Bose 一起站上了巅峰&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;物理原理-简单了解不用深入&#34;&gt; 物理原理  (简单了解，不用深入)&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;(1) 噪声：频率、强弱变化无规律、杂乱无章的机械波。&lt;br&gt;
(2) 传播特点：不同频率的声音，会有不同的传播特性，声波在传播过程中都会存在衰减。&lt;br&gt;
(3) 衰减：&lt;br&gt;
・扩散衰减&lt;br&gt;
物体振动发出的声波向四周传播，声波能量逐渐扩散开来。能量的扩散使得单位面积上所存在的能量减小，听到的声音就变得微弱。单位面积上的声波能量随着声源距离的平方而递减。&lt;br&gt;
・吸收衰减&lt;br&gt;
声波在固体介质中传播时，由于介质的粘滞性而造成质点之间的内摩擦，从而使一部分声能转变为热能；同时，由于介质的热传导，介质的稠密和稀疏部分之间进行热交换，从而导致声能的损耗，这就是介质的吸收现象。介质的这种衰减称为吸收衰减。通常认为，吸收衰减与声波频率的一次方、频率的平方成正比。&lt;br&gt;
・散射衰减&lt;br&gt;
当介质中存在颗粒状结构（如液体中的悬浮粒子、气泡，固体中的颗粒状结构、缺陷、搀杂物等）而导致的声波的衰减称散射衰减。通常认为当颗粒的尺寸远小于波长时，散射衰减与频率的四次方成正比；当颗粒尺寸与波长相近时，散射衰减与频率的平方成正比。&lt;br&gt;
(4) 总结：&lt;br&gt;
高频声音易于衰减，低频声音较难衰减。对于高频噪声，通常采用的是物理阻隔的方法，例如采用更多的吸声材料，这也是所谓的被动降噪，而对于低频噪声，吸声材料的作用就有限了，此时主动降噪也就成为了必要手段。而也正是因为对于高低频噪声不同的降噪特性，主动降噪和被动降噪技术被综合地使用很多降噪耳机中。&lt;/p&gt;
&lt;p&gt;(5) 相位：&lt;/p&gt;
&lt;p&gt;佛家里讲 “凡有所相，皆是虚妄”，俗语说 “相由心生”，这都是看得见的表相。&lt;/p&gt;
&lt;p&gt;在物理学中，&lt;strong&gt;相位&lt;/strong&gt;的描述是：&lt;strong&gt;周期性运动在各个时刻所处的不同状态&lt;/strong&gt;。不光描述机械运动的时候能遇到相位，在机械波、交流电甚至天文学上，这个词使用的也很普遍。这里我们只讲机械运动的相位（为了便于同学理解）。&lt;/p&gt;
&lt;p&gt;在机械振动中，&lt;strong&gt;相位描述的是做机械振动的物体的振动状态&lt;/strong&gt;。更多的是拿来对两个振动物体的振动步调进行比较。确切一些说；是拿来对做简谐运动的两个质点的振动步调进行比较。&lt;/p&gt;
&lt;p&gt;譬如，两个相同的单摆，把摆球拉起一定角度。如果摆球 A 和 B 同时释放，我们说它们的相位相同；如果 A 球领先于 B 球释放，我们说 A 球的相位领先（或超前）于 B 球，或者说 B 球的相位落后于 A 球。&lt;/p&gt;
&lt;p&gt;在振动图像上，我们来做个对比，更直观。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;譬如下面这个图：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://pic1.zhimg.com/50/v2-9843298321f819a15a978070d1d8ab48_hd.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;img src=&#34;https://pic1.zhimg.com/80/v2-9843298321f819a15a978070d1d8ab48_720w.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;可以看出，A 领先于 B 振动，A 的相位领先 B。&lt;/em&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;&lt;strong&gt;再来看这个图：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://pic1.zhimg.com/50/v2-e745ff59e343ae704581d4c83e3d3e3a_hd.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;img src=&#34;https://pic1.zhimg.com/80/v2-e745ff59e343ae704581d4c83e3d3e3a_720w.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;可以看出 A 和 B 同相振动。摆球 A 和摆球 B 在任一时刻位移方向总相同，振动方向也总相同，同时达到正向最大位移，也同时到达负向最大位移。这样的情况叫 A 和 B 同相位振动，简称同相振动。&lt;/em&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;&lt;strong&gt;再来看这个图：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://pic3.zhimg.com/50/v2-bf1c89e5e4c7ccc082672722c3190d3f_hd.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;img src=&#34;https://pic3.zhimg.com/80/v2-bf1c89e5e4c7ccc082672722c3190d3f_720w.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;可以看出，A 和 B 反相振动。&lt;/em&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;在任意时刻，A 和 B 的位移方向总相反，振动方向也总相反，A 位于正向最大位移处时 B 位于负向最大位移处，A 位于负向最大位移处时 B 位于正向最大位移处。这样的情况叫 A 和 B 反相位振动，简称反相振动。&lt;/em&gt;&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;降噪类型-两者分别举例对比讲解&#34;&gt; 降噪类型  (两者分别举例对比讲解)&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;https://pic4.zhimg.com/80/v2-60c73c6d1120af56587797b587881ef3_720w.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;(1) 主动降噪 (Active Noice Control)&lt;br&gt;
・原理&lt;br&gt;
如果两个声音频率是一样的，振幅也是一样的，但是相位偏偏相反：两个声波处处相反，彼此抵消，声音就被消除了。&lt;br&gt;
想要产生用于抵消噪声的声波，首先要得到噪声的信息才可以。主动降噪耳机设有反馈麦克风用于采集环境中的噪声信号。这里有一个先后顺序的问题：先采集噪声，但是要与噪声同时产生抵消音才能够降噪。所以处理器会根据噪声进行预测，预测出下一时刻噪声的情况，并产生相应抵消声波。&lt;/p&gt;
&lt;p&gt;为了保证降噪质量，还需要一个反馈麦克风用来检测所合成后的噪声是否真的变小了。这时处理器会根据这个反馈麦克风测量到的结果，对处理过程进行调整从而进一步降低合成后的噪声音量，这叫做自适应过程。&lt;br&gt;
拾音器（监测环境噪音）→处理芯片（分析噪音曲线）→扬声器（产生反响声波）&lt;br&gt;
(2) 被动降噪&lt;br&gt;
被动式降噪耳机利用物理特性将外部噪声与耳朵隔绝开，通过不同材质的阻塞物来防止噪音进入耳朵，就像放鞭炮用手捂着耳朵一样。&lt;/p&gt;
&lt;p&gt;厂商需要精心研究耳塞的材质与形状、腔体的材质与形状等会影响被动降噪效果的各项因素，只要设计平衡就可以获得优秀的降噪效果。&lt;strong&gt;材质大多是塑胶材料&lt;/strong&gt;，但&lt;strong&gt;耳机腔体外观就各有不同&lt;/strong&gt;了，&lt;/p&gt;
&lt;p&gt;但除了须着重在隔音效果，&lt;strong&gt;穿戴舒适度更是耳机的根本&lt;/strong&gt;，因此在形状设计的&lt;strong&gt;人体工学也非常重要&lt;/strong&gt;。&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;耳塞差异&#34;&gt; &lt;strong&gt;耳塞差异&lt;/strong&gt;&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;&lt;a href=&#34;https://www.techteller.com/wp-content/uploads/2020/08/%E7%88%86%E6%AC%BE%E5%9C%969.jpg&#34;&gt;&lt;img src=&#34;https://www.techteller.com/wp-content/uploads/2020/08/%E7%88%86%E6%AC%BE%E5%9C%969.jpg&#34; alt=&#34;一次看懂抗噪耳机原理－2020年8款ANC主动降噪真无线蓝牙耳机推荐&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;耳塞部分不同于耳机材质与形状，是消费者可以自行选择与更换的。常见的有矽胶、海绵、二节 / 三节胶耳塞。海绵与二节 / 三节胶耳塞可以带来最好的被动隔音效果。&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;海绵耳塞&#34;&gt; &lt;strong&gt;海绵耳塞&lt;/strong&gt;&lt;/span&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.techteller.com/wp-content/uploads/2020/05/2017-VP-Medium__43784.1509029289.500.750-1.png&#34;&gt;&lt;img src=&#34;https://www.techteller.com/wp-content/uploads/2020/05/2017-VP-Medium__43784.1509029289.500.750-1.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;em&gt;image source：complyfoam&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;除了&lt;strong&gt;隔音效果拔群&lt;/strong&gt;以外，因为海绵可压缩，能让耳塞&lt;strong&gt;更贴合耳朵&lt;/strong&gt;借此带来优秀的舒适感。但海绵耳塞因材质特性&lt;strong&gt;会吸收音乐的高频部分与细节&lt;/strong&gt;，&lt;strong&gt;造成音质下滑&lt;/strong&gt;。且海绵耳塞&lt;strong&gt;易脏&lt;/strong&gt;，每隔一段时间就需要更换，相对其他耳塞属于消耗品。海绵厂商中比较知名的厂商是&lt;strong&gt; Comply&lt;/strong&gt;。&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;矽胶耳塞&#34;&gt; &lt;strong&gt;矽胶耳塞&lt;/strong&gt;&lt;/span&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.techteller.com/wp-content/uploads/2020/05/spinfit-tips_850x-1.png&#34;&gt;&lt;img src=&#34;https://www.techteller.com/wp-content/uploads/2020/05/spinfit-tips_850x-1.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;em&gt;image source： Spinfit&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;矽胶耳塞的隔音效果是最差的，当然这只是相比出来的结果，不代表矽胶耳塞的隔音都很差，只是更&lt;strong&gt;需注意耳塞尺寸避免漏音&lt;/strong&gt;。音质在高频与细节部分比海绵耳塞表现好，低频则是较海绵耳塞少。&lt;/p&gt;
&lt;p&gt;矽胶耳塞算是在&lt;strong&gt;音质&lt;/strong&gt;、&lt;strong&gt;舒适度&lt;/strong&gt;、&lt;strong&gt;隔音&lt;/strong&gt;、&lt;strong&gt;耐用度获得良好平衡&lt;/strong&gt;的材质，因此被耳机厂商广泛使用为标配耳塞。这几年矽胶耳塞最知名的是&lt;strong&gt; Spinfit&lt;/strong&gt;。&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;二节-三节胶耳塞&#34;&gt; &lt;strong&gt;二节 / 三节胶耳塞&lt;/strong&gt;&lt;/span&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.techteller.com/wp-content/uploads/2020/05/Earplug_14-694x462-2.jpg&#34;&gt;&lt;img src=&#34;https://www.techteller.com/wp-content/uploads/2020/05/Earplug_14-694x462-2.jpg&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;em&gt;image source：unwire&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;二节 / 三节胶耳塞在&lt;strong&gt;隔音效果&lt;/strong&gt;与&lt;strong&gt;音质获得绝佳效果&lt;/strong&gt;，综合了海绵与矽胶耳塞的优点，&lt;strong&gt;全频表现都很好&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;但缺点也非常明显：「&lt;strong&gt;舒适度较差&lt;/strong&gt;」，这部分我认为算是影响蛮大的缺点，因为耳塞是会直接接触耳朵，而耳朵又是人体比较敏感的部位，如果戴起来不舒适在体感上很容易被放大。因此 Daniel 认为二 / 三节胶耳塞可以说是种&lt;strong&gt;优劣分明的耳塞&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;除了上列三种材质的耳塞也有&lt;strong&gt;复合材质耳塞&lt;/strong&gt;，像是矽胶与海绵同时使用的耳塞，为的就是想同时获得两种材质的优点。&lt;/p&gt;
&lt;p&gt;耳塞对耳机整体使用的体验影响甚大，在隔音方面其实只要&lt;strong&gt;选择适合自己的尺寸&lt;/strong&gt;加上&lt;strong&gt;正确的穿戴耳机&lt;/strong&gt;，以矽胶与海绵耳塞来说表现就是在 80 分与 95 分的差别而已，比较后依然听得出差异但都能应付日常生活使用。&lt;/p&gt;
&lt;p&gt;在音质方面则是比较能感受且使用上也确实有差异，海绵耳塞的音质理论上都会被影响，这也是矽胶耳塞非常明显的优势。&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;spinfit-耳塞&#34;&gt; &lt;strong&gt;Spinfit 耳塞&lt;/strong&gt;&lt;/span&gt;&lt;/h4&gt;
&lt;p&gt;矽胶耳塞随着技术演进，在隔音方面的表现也越来越优秀。像是 Daniel 平常使用的 Spinfit 矽胶耳塞，除了&lt;strong&gt;舒适&lt;/strong&gt;、&lt;strong&gt;听感表现佳&lt;/strong&gt;在&lt;strong&gt;隔音方面也非常棒&lt;/strong&gt;，耳机无须开大声就可以隔绝掉大多数外界声音。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;选择自己适合及调性的的耳塞&lt;/strong&gt;，&lt;strong&gt;是轻松且花费相对低的方法&lt;/strong&gt;。因此 Daniel 蛮推荐大家可以多试试几种耳塞，说不定能为你带来意想不到的新感觉。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;计算机领域技术&#34;&gt; 计算机领域技术&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;前馈降噪：接收外部噪音，计算出反相噪声在喇叭里播放，内外抵消。但耳道内还是会有一定残留&lt;/p&gt;
&lt;p&gt;反馈降噪：接收耳道内噪音，计算反相，直接抵消耳道内噪音，并且还能对耳机播放的声音进行反馈并动态调节。但直接反馈效果也不好。&lt;/p&gt;
&lt;p&gt;3、由喇叭发出带有噪音的反向声波的音乐（在播放音乐的同时对外部噪音进行中和处理）。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://pic.hifidiy.net/www/2013/03/14/01_87.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;一、前馈式主动降噪设计：如图中所示，前馈式设计是将麦克风与耳机喇叭单元隔离开来（就是将麦克风的声音采集点设计在耳机腔体表面），确保喇叭产生的声波对麦克风的影响最小。这种设计为最直接的噪音采集方式，麦克风采集噪音信号之后，通过传递函数函数 G（w) 处理，通过喇叭发出反向声波，中和噪音。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://pic.hifidiy.net/www/2013/03/14/01_88.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;二、反馈式主动降噪设计：如图中所示，反馈式主动降噪将噪音采集麦克风设计在了喇叭附近，相对于前馈式，反馈式所采集到的噪音更接近于人耳所能听到的噪音，但是这种设计的一大缺点就是麦克风无法很好的分辨喇叭发出的声音及噪音的区别，如果音乐当中出现与噪音类似的声音，也会被识别为噪音，被进行处理，这在一定程度上造成了音乐的失真，如何避免这一现象，是体现各个厂商设计实力的所在。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://pic.hifidiy.net/www/2013/03/14/01_89.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;三、前馈与反馈结合式：如图中所示，这种方式就是集合以上两种降噪设计，拥有两个麦克风，这种设计除了会增加物料成本以外，对于函数 G（w）的建立也是一个不小的挑战，不过目前市面上已经有不少这类降噪耳机产品。&lt;/p&gt;
&lt;p&gt;总结：虽然笔者上面的介绍较为简洁，但降噪技术可真心没这么简单，想要做好一款真正实用的降噪耳机产品，对很多厂商来说是一件很头疼的问题，这也是为什么市面上你能见到的降噪耳机产品一般较贵的原因之一（销量小也是原因之一)。&lt;/p&gt;
&lt;p&gt;单前馈：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://5b0988e595225.cdn.sohucs.com/images/20180427/fbb9f0c8e15b44df9fab9ca11259888d.jpeg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;单反馈：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://5b0988e595225.cdn.sohucs.com/images/20180427/c0f9b504aa3a495991e00b3d9cca49b4.jpeg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;我们可以把&lt;strong&gt;前馈麦&lt;/strong&gt;形象地当作是一个干活差不多就行的凑合星人：比起质量，他更追求速度。听到某个噪声后，他只负责&lt;strong&gt;报告给 PCB&lt;/strong&gt;，然后&lt;strong&gt;就去接着监听别的声音了&lt;/strong&gt;；&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;反馈麦&lt;/strong&gt;则完全不同，是一位特别忠于职守、一丝不苟的严谨派。只要是他监听到的噪声，他就想要&lt;strong&gt;负责到底&lt;/strong&gt;，&lt;strong&gt;不处理干净声音就不罢休&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;那么，双麦一起降噪，又是什么样子呢？&lt;/p&gt;
&lt;p&gt;前馈 + 反馈：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://5b0988e595225.cdn.sohucs.com/images/20180427/327c77c307594018b461504a4aa56a12.jpeg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;看到这，相信你脑中也有了大致结论：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;strong&gt;前馈降噪频段宽、深度小；&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;反馈降噪频段短、深度大；&lt;/p&gt;
&lt;p&gt;1.ANC 降噪（Active Noise Control，主动降噪），&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;工作原理是通过麦克风收集外部的环境噪音，然后经过系统变换为一个反相的声波加到喇叭端，最终人耳听到的声音是：环境噪音 + 反相的环境噪音，两种噪音叠加从而实现噪音降低。&lt;br&gt;
拾音器（监测环境噪音）→处理芯片（分析噪音曲线）→扬声器（产生反响声波）→完成降噪&lt;/p&gt;
&lt;p&gt;简单的说，假设出现的噪音为 A，通过外部的拾音器监测到后，那么耳机会瞬间产生 - A 的声音，两者在耳内相互抵消，以此实现降噪的功能。可以说其实你的耳朵已经 “听” 了噪音，但是同时也听到了 “降噪音”，两者在你耳中互相抵消实现降噪。&lt;/p&gt;
&lt;p&gt;主动降噪根据拾音麦克风位置的不同，分为前馈式主动降噪与反馈式主动降噪。&lt;/p&gt;
&lt;p&gt;这么一来，这个耳机需要一段的算法处理时间，先学习噪声，这个学习需要时间，然后再把学习到的噪声相位反转，有一个自适应调整期。&lt;/p&gt;
&lt;p&gt;主动降噪耳机价格昂贵，但是一般效果优秀，佩戴舒适。但是需要&lt;strong&gt;独立电池供电&lt;/strong&gt;，大多数被动降噪耳机可以不耗电使用（也不主动降噪）&lt;/p&gt;
&lt;p&gt;2.ENC 降噪 ENC（Environmental Noise Cancellation，环境降噪技术），通过双麦克风阵列，精准计算通话者说话的方位，在保护主方向目标语音的同时，去除环境中的各种干扰噪声。能有效抑制 90% 的反向环境噪声，由此降低环境噪声最高可达 35dB 以上。&lt;/p&gt;
&lt;p&gt;ENC 与 ANC 最明显的区别就在于，ANC 的受益人为使用耳机本人，通过 ANC 的功能，可以让用户自身免受环境噪音干扰；ENC 的受益人则是通话的另一方，通过 ENC 减少环境噪音对通话的影响，让对方听到纯净的语音。ANC 让自身听感环境更加安静，而 ENC 让通话的另一端听感环境更加安静。&lt;/p&gt;
&lt;p&gt;ENC 会使用&lt;strong&gt;双麦克风&lt;/strong&gt;，其中&lt;strong&gt;一个负责人声收音&lt;/strong&gt;，&lt;strong&gt;另一个负责接收环境声音&lt;/strong&gt;，并透过演算法将人声麦克风收到的声音与环境声音重叠的部分消除，这样就可以精准的将环境声音过滤。&lt;/p&gt;
&lt;p&gt;通过双麦克风阵列，精准计算通话者说话的方位，在保护主方向目标语音的同时，去除环境中的各种干扰噪声。&lt;/p&gt;
&lt;p&gt;ENC 全称是 Environmental Noise Cancellation（环境降噪技术）。ENC 包括单麦环境降噪和双麦环境降噪。单麦环境降噪通常以环境噪声为随机平稳加性噪声、且与语音信号不相关为前提估计噪声，然后进行滤波。因此，单麦环境降噪的效果比较差。双麦环境降噪则是通过双麦克风阵列，精准计算通话者说话的方位，在保护目标语音的同时，滤除环境中的各种干扰噪声。其工作原理大致如下：在进行环境噪声滤波模块计算之前，先校正语音麦克风和参考麦克风的增益，以及两个麦克风的时延。然后检测语音麦克风采集到的数据是否为语音段。若为语音段（即上行通话），则根据参考麦克风采集到的环境噪声和语音麦克风的语音数据，预估环境噪声，并计算相应的噪声抑制参数，最终由滤波器模块滤出环境噪声；反之，不进行环境噪声滤除，上行通话输出为静音。ENC 主要降低通话时非目标语音噪声，确保通话清晰。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://www.zowee.com.cn/upload/image/20200724/20200724152137_1134.png&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;3.DSP 降噪的原理和 ANC 降噪相似。但 DSP 降噪正反向噪音直接在系统内部相互中和抵消。DSP 与 ANC 的区别：（1）混叠的信号类型不同：ANC 混叠声信号，而 DSP 混叠数字电信号。（2）混叠的位置不同：ANC 是在喇叭到耳膜这段空气中，进行声信号的混叠，而 DSP 是在耳机系统内部进行电信号的混叠。&lt;/p&gt;
&lt;p&gt;4.CVC 降噪 CVC（Clear Voice Capture）是通话软件降噪技术。主要针对通话过程中产生的回声。通过全双工麦克风消噪软件，提供通话的回声和环境噪音消除功能，是目前蓝牙通话耳机中最先进的降噪技术。&lt;/p&gt;
&lt;p&gt;cVc 可以说是使用高通晶片蓝牙耳机的独家技术，与 ENC 的概念相同都是透过麦克风收音去辨识分离环境音与人声，算是通话降噪的指标，但偶有听说 CVC 的降噪效果过强造成人声也被消除的状况。&lt;/p&gt;
&lt;p&gt;尽管高通的 cVc 技术较知名，但&lt;strong&gt; ENC 与 cVc 并无优劣之分&lt;/strong&gt;，两者都可以为通话带来超过 30 分贝以上的降噪效果，ENC 只要厂商适当调整不会输给 cVc，基本上&lt;strong&gt;有通话降噪技术就可视为通话品质有一定的水准&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;DSP 技术主要受益方是耳机使用者本人，而 CVC（消除回声）主要使通话的另一方受益。&lt;/p&gt;
&lt;p&gt;这里我总结了一个思维导图给大家。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://pic1.zhimg.com/80/v2-cc1e9ffad4c0d9b4b557eb0684393ef0_720w.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;如果说 ANC 让自身听感环境更加安静，那 ENC 则是让通话的另一端听感环境更加安静。而 CVC 可以理解成一种算法或者软件，它主要针对通话过程中的回音，受益人为通话的另一端，ENC 则是针对环境噪声，虽然受益的也是通话的另一端，但是针对的干扰信号不同。DSP 降噪虽然跟 ANC 主动降噪原理类似，但是中和声波的位置是不一样的，这下搞明白了吗？&lt;/strong&gt;&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;其他&#34;&gt; 其他&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;ANC 主动降噪因为发声器（喇叭）需要同时发出声音与抵销外界噪音的反向声波，因此&lt;strong&gt;音质部分势必会受到干扰&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;多数追求音质的人都会重视器材的「&lt;strong&gt;保真度&lt;/strong&gt;」，即声音细节是否能妥善还原，但开启 ANC 主动降噪模式后，喇叭发出的&lt;strong&gt;反向声波就可能造成声音的细节部分被掩盖流失&lt;/strong&gt;，这时就会造成耳机音质变差、听起来闷闷的情形。&lt;/p&gt;
&lt;p&gt;除了最常见的麦克风收音外，科技大厂 Huawei 华为在自家真无线蓝牙耳机 Freebuds 3 上使用了「&lt;strong&gt;骨声纹&lt;/strong&gt;」感应装置，技术类似骨传导耳机的发声方式只是变为收音，借此来强化人声收音，算是非常特别的技术。&lt;/p&gt;
&lt;p&gt;大家好，我是来自腾讯多媒体实验室的李松南，本次分享将为大家介绍传统降噪和深度学习降噪方法，以及降噪技术未来的发展趋势。腾讯多媒体实验室专注于多媒体技术领域的前沿技术探索、研发、应用和落地，在长期积累中精心打造出三大核心能力，分别是：音视频编解码、网络传输和实时通信；多媒体内容处理、分析、理解和质量评估；沉浸式媒体系统设计和端到端解决方案。本次分享中的内容就属于多媒体内容处理的一部分。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://segmentfault.com/img/remote/1460000021721653&#34; alt=&#34;图像视频降噪的现在与未来——从经典方法到深度学习&#34;&gt;&lt;/p&gt;
&lt;p&gt;上图是腾讯多媒体实验室常年积累起来的视频处理能力，包括视频降噪、去压缩失真、视频去抖动、夜景增强、视频超分、视频锐化等，这些能力已经应用于腾讯的许多产品，比如腾讯云、全民 K 歌、企鹅电竞、微视、QQ 空间等。目前团队正在向腾讯云推出画质修复功能，已经开发和计划开发的技术，包括视频超分、去伪影、去抖动、去划痕与雪花、插帧、HDR，还有下面主要介绍的视频降噪技术。&lt;/p&gt;
&lt;p&gt;图像、视频从采集到播放的整个生命周期中会经历各种各样的处理过程，比如采集、剪辑、编码、转码、传输、显示等，每个处理过程都会引入失真。“噪声” 就是在信号采集过程中引入的一种普遍失真。降低噪声强度可以使图像主观效果更好。另外，在图像、视频压缩时也不必浪费码率在编码噪声上。同时，会使得视频编码中的运动估计更准确、熵编码速度更快。&lt;/p&gt;
